<template>
    <div
        class="contact-card"
        @mouseenter="onInternalEnter"
        @mouseleave="onInternalLeave"
    >
        <div class="modal-title">
            <h2>{{ dataDictionary.title || 'Get in Touch' }}</h2>
        </div>

        <div class="contact-content">
            <!-- Loop through the array of social objects -->
            <div 
                v-for="(contact, index) in dataDictionary.socials" 
                :key="index" 
                class="contact-items"
            >
                <label
                    class="section-label"
                    for="{{ contact.type }}">
                    {{ contact.type }}:
                </label>
                <div
                    class="contact-detail"
                    id="{{ contact.type }}
                ">
                    {{ contact.details }}
                    <button
                        class="copy-btn" 
                        @click="copyToClipboard(contact.details)"
                        title="Copy to clipboard"
                    >
                    <ion-icon class="ionic-icon" name="copy"></ion-icon>
                </button>
                </div>

            </div>
        </div>
    </div>
</template>

<script>
    import { toast } from "@/utilities/toaster";

    export default {
        name: "ContactChild",
        props: {
            dataDictionary: {
                type: Object, // Changed to Object if you're using standard JS objects
                required: true
            }
        },
        methods: {
            onInternalEnter() {
                this.$emit('mouseenter-child', this.$options.name);
            },
            onInternalLeave() {
                this.$emit('mouseleave-child');
            },


            async copyToClipboard(text) {
            // 1. Try the modern API first
            if (navigator.clipboard && window.isSecureContext) {
                try {
                    await navigator.clipboard.writeText(text);
                    console.log('Copied using Clipboard API');
                    toast.success("Contact copied");
                    return;
                } catch (err) {
                    console.error('Clipboard API failed:', err);
                }
            }

            // 2. Fallback for non-secure contexts (HTTP) or older browsers
            const textArea = document.createElement("textarea");
            textArea.value = text;
            // Ensure the textarea is not visible but still in the DOM
            textArea.style.position = "fixed";
            textArea.style.left = "-9999px";
            textArea.style.top = "0";
            document.body.appendChild(textArea);
            textArea.focus();
            textArea.select();

            try {
                const successful = document.execCommand('copy');
                if (successful) toast.success("Contact copied");

            } catch (err) {
                console.error('Fallback failed:', err);
            }

            document.body.removeChild(textArea);
        }
        }
    }
</script>
